import { useCallback, useEffect, useMemo, useState } from "react";
import { useNavigate, useSearchParams } from "react-router-dom";
import { calculatePortfolioSummary, formatMoney } from "../../domain/portfolio.js";
import { dataFoundation } from "../../domain/dataFoundation.js";
import { buyFromRadar, buyPosition, sellPosition } from "../../domain/trading.js";
import { fetchPrintings, refreshTrackedPrices, searchCards, toTrackedCard } from "../../services/scryfall.js";
import { useAppState } from "../../state/AppState.jsx";
import { TabulatorTable } from "../shared/TabulatorTable.jsx";
import { CardIdentity, DataTable, FilterBar, MetricBand, Modal, Notice, TradeForm, ViewHeader } from "../shared/ui.jsx";

const date = value => value ? new Date(value).toLocaleDateString() : "-";
const number = value => Number(value || 0);
const signedMoney = value => `${number(value) >= 0 ? "+" : "-"}${formatMoney(Math.abs(number(value)))}`;
const color = item => (item.color_identity || item.colors || []).join("") || "C";
const rarity = item => item.rarity ? `${item.rarity[0].toUpperCase()}${item.rarity.slice(1)}` : "-";
const printing = item => `${String(item.set_code || item.set || "-").toUpperCase()} #${item.collector_number || "-"}${item.foil ? " F" : ""}`;
const percent = value => `${number(value) > 0 ? "+" : ""}${number(value).toFixed(1)}%`;
const ageDays = value => value ? Math.max(0, Math.floor((Date.now() - new Date(value).getTime()) / 86400000)) : 0;
const noteMatches = (note, item) => note.cardKey === `${item.scryfall_id || item.id}|${item.foil ? "foil" : "nonfoil"}` || note.cardId === item.id || note.scryfall_id === item.scryfall_id;

function useNotices() {
  const [notice, setNotice] = useState(null);
  return { notice, dismiss: useCallback(() => setNotice(null), []), show: (message, tone = "") => setNotice({ message, tone }) };
}

function CardDetail({ item, source, onClose, initialPanel = "" }) {
  const { state, updateSlice } = useAppState();
  const [text, setText] = useState("");
  const [printings, setPrintings] = useState([]);
  const [printingsStatus, setPrintingsStatus] = useState("");
  const [historyOpen, setHistoryOpen] = useState(false);
  const [comparablesOpen, setComparablesOpen] = useState(false);
  const [market, setMarket] = useState({ marketPrice: "", currentSellers: "", currentQuantity: "", rawText: "" });
  useEffect(() => {
    if (!item) return undefined;
    const controller = new AbortController();
    setPrintingsStatus("Loading comparable printings…");
    fetchPrintings(item, controller.signal).then(rows => { setPrintings(rows.slice(0, 16)); setPrintingsStatus(""); }).catch(error => { if (error.name !== "AbortError") setPrintingsStatus(error.message); });
    return () => controller.abort();
  }, [item]);
  useEffect(() => {
    setHistoryOpen(Boolean(item) && initialPanel === "history");
    setComparablesOpen(false);
  }, [item, initialPanel]);
  if (!item) return null;
  const key = `${item.scryfall_id || item.id}|${item.foil ? "foil" : "nonfoil"}`;
  const notes = state.cardNotes.filter(note => note.cardKey === key || note.cardId === item.id || note.cardId === item.scryfall_id).sort((a, b) => new Date(b.updatedAt || b.createdAt) - new Date(a.updatedAt || a.createdAt));
  const tcg = `https://www.tcgplayer.com/search/magic/product?productLineName=magic&q=${encodeURIComponent(item.name)}`;
  const scryfall = `https://scryfall.com/card/${String(item.scryfall_id || item.id).replace(/\|.*$/, "")}`;
  const owned = source !== "radar" && state.specs.some(row => row.id === item.id);
  const slice = owned ? "specs" : "radar";
  const latestMarket = state.marketObservations.filter(row => row.cardId === item.id || row.cardId === item.scryfall_id).sort((a, b) => new Date(b.checkedAt) - new Date(a.checkedAt))[0];
  const target = number(owned ? item.exitTarget : item.entryTarget);
  const targetDistance = target ? ((number(item.currentPrice) - target) / target) * 100 : null;
  function editPlan(field, value) {
    updateSlice(slice, rows => rows.map(row => row.id === item.id ? { ...row, [field]: field === "holdTime" ? value : number(value) } : row));
  }
  function addNote(event) {
    event.preventDefault();
    if (!text.trim()) return;
    const now = new Date().toISOString();
    updateSlice("cardNotes", rows => [{ id: crypto.randomUUID(), cardKey: key, cardId: item.id, scryfall_id: item.scryfall_id, finish: item.foil ? "foil" : "nonfoil", cardName: item.name, set_code: item.set_code, collector_number: item.collector_number, text: text.trim(), createdAt: now, updatedAt: now }, ...rows]);
    setText("");
  }
  const history = state.priceSnapshots.filter(row => row.cardId === item.scryfall_id || row.cardId === item.id).sort((a, b) => String(a.date).localeCompare(String(b.date)));
  function saveMarket(event) {
    event.preventDefault(); const now = new Date().toISOString();
    updateSlice("marketObservations", rows => [{ id: crypto.randomUUID(), cardId: item.id, name: item.name, source: "tcgplayer", checkedAt: now, url: tcg, marketPrice: number(market.marketPrice), currentSellers: number(market.currentSellers), currentQuantity: number(market.currentQuantity), rawText: market.rawText }, ...rows]);
    setMarket({ marketPrice: "", currentSellers: "", currentQuantity: "", rawText: "" });
  }
  const comparableRows = printings.map(card => { const cardId = String(card.scryfall_id || card.id).replace(/\|.*$/, ""); const setCode = card.set?.toUpperCase?.() || card.set_code || "-"; const nonfoil = number(card.prices?.usd || (!card.foil ? card.currentPrice : 0)); const foil = number(card.prices?.usd_foil || (card.foil ? card.currentPrice : 0)); return <a key={card.id} href={`https://scryfall.com/card/${cardId}`} target="_blank" rel="noreferrer"><span>{card.set_name} · {setCode} #{card.collector_number}</span><strong>{nonfoil ? formatMoney(nonfoil) : "-"}</strong><small>{foil ? `Foil ${formatMoney(foil)}` : "No foil price"}</small></a>; });
  return <><Modal open title={item.name} onClose={onClose} compactDetail><div className="compact-detail"><div className="compact-detail-identity"><strong>{String(item.set_code || "-").toUpperCase()} #{item.collector_number || "-"} · {item.foil ? "Foil" : "Nonfoil"}</strong><span>{item.set_name || "Exact tracked printing"}</span></div><section className="compact-detail-metrics"><div><span>Current</span><strong>{formatMoney(item.currentPrice)}</strong></div><div><span>{owned ? "Cost basis" : "Entry"}</span><strong>{number(owned ? item.buyPrice : item.entryTarget) ? formatMoney(owned ? item.buyPrice : item.entryTarget) : "-"}</strong></div><div><span>Exit</span><strong>{number(item.exitTarget) ? formatMoney(item.exitTarget) : "-"}</strong></div><div><span>Quantity</span><strong>{owned ? number(item.qty) : number(item.plannedQty || 1)}</strong></div></section><div className="compact-detail-grid"><div className="compact-detail-column"><section className="compact-detail-section plan"><header><h4>Plan / Evaluation</h4><span>{targetDistance === null ? "Target needed" : `${percent(targetDistance)} vs target`}</span></header><div className="compact-plan-fields"><label><span>Entry</span><input type="number" step="0.01" value={item.entryTarget || ""} placeholder="Set" onChange={event => editPlan("entryTarget", event.target.value)} /></label><label><span>Exit</span><input type="number" step="0.01" value={item.exitTarget || ""} placeholder="Set" onChange={event => editPlan("exitTarget", event.target.value)} /></label>{owned && <label><span>Hold</span><input value={item.holdTime || ""} placeholder="Months" onChange={event => editPlan("holdTime", event.target.value)} /></label>}</div><div className="compact-evaluation"><span>Source <strong>{owned ? "Positions" : "Radar"}</strong></span><span>Market <strong>{latestMarket?.marketPrice ? formatMoney(latestMarket.marketPrice) : "No check"}</strong></span><span>Checked <strong>{latestMarket ? date(latestMarket.checkedAt) : "Due"}</strong></span></div></section><section className="compact-detail-section market"><header><h4>Market Check</h4><span>{latestMarket ? `Saved ${date(latestMarket.checkedAt)}` : "TCG snapshot"}</span></header><form className="compact-market-form" onSubmit={saveMarket}><label><span>Market price</span><input type="number" min="0" step="0.01" value={market.marketPrice} onChange={event => setMarket(current => ({ ...current, marketPrice: event.target.value }))} /></label><label><span>Sellers</span><input type="number" min="0" value={market.currentSellers} onChange={event => setMarket(current => ({ ...current, currentSellers: event.target.value }))} /></label><label><span>Quantity</span><input type="number" min="0" value={market.currentQuantity} onChange={event => setMarket(current => ({ ...current, currentQuantity: event.target.value }))} /></label><label className="raw"><span>Raw observation</span><input value={market.rawText} onChange={event => setMarket(current => ({ ...current, rawText: event.target.value }))} placeholder="Condition or pasted market context" /></label><button type="submit">Save Check</button></form></section></div><div className="compact-detail-column"><section className="compact-detail-section notes"><header><h4>Notes</h4><span>{notes.length ? `${notes.length} saved` : "-"}</span></header>{notes[0] ? <article className="compact-latest-note"><small>{new Date(notes[0].updatedAt || notes[0].createdAt).toLocaleString()}</small><p>{notes[0].text}</p></article> : <p className="compact-empty">No notes yet.</p>}<form className="compact-note-form" onSubmit={addNote}><input value={text} onChange={event => setText(event.target.value)} placeholder="Add note" /><button type="submit">Add Note</button></form>{notes.length > 1 && <details className="compact-note-history"><summary>Show older notes ({notes.length - 1})</summary>{notes.slice(1).map(note => <p key={note.id}>{note.text}</p>)}</details>}</section><section className="compact-detail-section context"><header><h4>Card Context</h4><span>{rarity(item)} · {color(item)}</span></header><strong>{item.type_line || "Card data unavailable"}</strong><p className="compact-oracle">{item.oracle_text || "Oracle text unavailable."}</p><small>Artist: {item.artist || "-"}</small><div className="compact-detail-links"><a href={scryfall} target="_blank" rel="noreferrer">Scryfall</a><a href={tcg} target="_blank" rel="noreferrer">TCGplayer</a></div></section><section className="compact-secondary-actions"><button type="button" onClick={() => setHistoryOpen(true)}>Price History <span>{history.length}</span></button><button type="button" onClick={() => setComparablesOpen(true)}>Comparable Printings <span>{printingsStatus || printings.length}</span></button></section></div></div></div></Modal><Modal open={historyOpen} title={`${item.name} · Price History`} onClose={() => setHistoryOpen(false)} wide><PriceHistory rows={history} current={item.currentPrice} /></Modal><Modal open={comparablesOpen} title={`${item.name} · Comparable Printings`} onClose={() => setComparablesOpen(false)} wide>{printingsStatus && <p className="muted">{printingsStatus}</p>}{printings.length ? <div className="comparables">{comparableRows}</div> : !printingsStatus && <p className="muted">No comparable printings found.</p>}</Modal></>;
}

function PriceHistory({ rows, current }) {
  const points = rows.slice(-20);
  if (!points.length) return <p className="muted">No saved daily snapshots yet. Refresh prices in Admin to begin history.</p>;
  const values = points.map(row => number(row.price)); const min = Math.min(...values); const max = Math.max(...values); const range = max - min || 1;
  const path = points.map((row, index) => `${index ? "L" : "M"}${(index / Math.max(1, points.length - 1)) * 100},${38 - ((number(row.price) - min) / range) * 34}`).join(" ");
  return <div className="price-history"><svg viewBox="0 0 100 42" role="img" aria-label={`Price history from ${formatMoney(min)} to ${formatMoney(max)}`} preserveAspectRatio="none"><path d={path} /></svg><div><span>{date(points[0].date)} · {formatMoney(values[0])}</span><strong>Current {formatMoney(current)}</strong><span>{date(points.at(-1).date)} · {formatMoney(values.at(-1))}</span></div></div>;
}

function SearchPanel({ initialQuery = "", onAdd }) {
  const [query, setQuery] = useState(initialQuery);
  const [results, setResults] = useState([]);
  const [status, setStatus] = useState("");
  const [choice, setChoice] = useState(null);
  async function submit(event) {
    event.preventDefault(); setStatus("Searching Scryfall…"); setResults([]);
    try { const cards = await searchCards(query); setResults(cards); setStatus(cards.length ? "" : "No paper printings found."); }
    catch (error) { setStatus(error.message); }
  }
  return <section className="search-panel module-context-card module-context-card--wide module-context-card--search"><form onSubmit={submit}><label><span>Search / Add Candidate</span><div className="search-row"><input value={query} onChange={event => setQuery(event.target.value)} placeholder="Card name or set #, e.g. MH3 123" /><button type="submit">Search</button></div></label></form>{status && <p className="muted">{status}</p>}{results.length > 0 && <div className="search-results">{results.map(card => <button type="button" key={card.id} onClick={() => setChoice(card)}><span>{card.image_uris?.small && <img src={card.image_uris.small} alt="" />}<strong>{card.name}</strong></span><small>{card.set_name} · {card.set.toUpperCase()} #{card.collector_number}<br />{card.prices.usd ? formatMoney(card.prices.usd) : "No nonfoil price"}{card.prices.usd_foil ? ` · Foil ${formatMoney(card.prices.usd_foil)}` : ""}</small></button>)}</div>}<Modal open={Boolean(choice)} title="Add exact printing" onClose={() => setChoice(null)}>{choice && <AddCandidateForm card={choice} onCancel={() => setChoice(null)} onAdd={options => { onAdd(toTrackedCard(choice, options)); setChoice(null); }} />}</Modal></section>;
}

function AddCandidateForm({ card, onAdd, onCancel }) {
  const [foil, setFoil] = useState(!card.finishes?.includes("nonfoil")); const [plannedQty, setQty] = useState(1); const [entryTarget, setEntry] = useState("");
  return <form className="react-form" onSubmit={event => { event.preventDefault(); onAdd({ foil, plannedQty, entryTarget }); }}><div className="trade-card-line"><strong>{card.name}</strong><span>{card.set_name} · #{card.collector_number}</span></div><div className="form-grid"><label><span>Finish</span><select value={foil ? "foil" : "nonfoil"} onChange={event => setFoil(event.target.value === "foil")}><option value="nonfoil" disabled={!card.finishes?.includes("nonfoil")}>Nonfoil</option><option value="foil" disabled={!card.finishes?.includes("foil")}>Foil</option></select></label><label><span>Planned quantity</span><input type="number" min="1" value={plannedQty} onChange={event => setQty(event.target.value)} /></label><label><span>Entry target</span><input type="number" min="0" step="0.01" value={entryTarget} onChange={event => setEntry(event.target.value)} placeholder="Optional" /></label></div><div className="modal-actions"><button type="button" className="secondary" onClick={onCancel}>Cancel</button><button type="submit">Add to Radar</button></div></form>;
}

export function RadarView() {
  const { state, updateSlice, updateState } = useAppState(); const [params] = useSearchParams(); const [filter, setFilter] = useState(""); const [trade, setTrade] = useState(null); const [detail, setDetail] = useState(null); const [detailPanel, setDetailPanel] = useState(""); const notices = useNotices();
  const rows = state.radar.filter(item => [item.name, item.set_code, item.set_name, item.collector_number].join(" ").toLowerCase().includes(filter.toLowerCase()));
  function add(item) { if (state.radar.some(row => row.id === item.id)) return notices.show(`${item.name} is already on Radar.`, "warning"); updateSlice("radar", list => [item, ...list]); notices.show(`${item.name} added to Radar.`); }
  function updateRadar(item, changes) { updateSlice("radar", list => list.map(row => row.id === item.id ? { ...row, ...changes } : row)); }
  function latestMarket(item) { return state.marketObservations.filter(row => row.cardId === item.id || row.cardId === item.scryfall_id).sort((a, b) => new Date(b.checkedAt) - new Date(a.checkedAt))[0]; }
  function noteCount(item) { return state.cardNotes.filter(note => noteMatches(note, item)).length; }
  function historyCount(item) { return state.priceSnapshots.filter(row => row.cardId === item.id || row.cardId === item.scryfall_id).length; }
  function openDetail(item, panel = "") { setDetailPanel(panel); setDetail(item); }
  const compactMoney = value => number(value) ? `$${number(value).toLocaleString(undefined, { maximumFractionDigits: 2 })}` : "-";
  const columns = [
    { key: "name", label: "Card", minWidth: 180, widthGrow: 1, widthShrink: 1, render: item => <button className="table-link" onClick={() => openDetail(item)}><CardIdentity item={item} />{state.specs.some(row => row.id === item.id) && <span className="ms-ownership-indicator" title="Also owned in Positions">Owned</span>}</button> },
    { key: "set_code", label: "Set", align: "center", width: 48, widthShrink: 0, format: item => String(item.set_code || "-").toUpperCase(), title: item => item.set_name || "" },
    { key: "collector_number", label: "#", align: "center", width: 48, widthShrink: 0, format: item => `${String(item.collector_number || "").padStart(3, "0")}${item.foil ? " F" : ""}` },
    { key: "rarity", label: "Rarity", align: "center", width: 44, widthShrink: 0, format: item => item.rarity ? item.rarity[0].toUpperCase() : "-" },
    { key: "color", label: "Color", align: "center", width: 44, widthShrink: 0, format: color },
    { key: "currentPrice", label: "Scryfall", align: "money", width: 72, widthShrink: 0, sortValue: item => number(item.currentPrice), format: item => compactMoney(item.currentPrice) },
    { key: "addedDate", label: "Added", align: "center", width: 72, widthShrink: 0, sortValue: item => item.addedDate ? new Date(item.addedDate).getTime() : 0, format: item => date(item.addedDate), title: item => item.addedDate ? new Date(item.addedDate).toLocaleString() : "No added date" },
    { key: "entryTarget", label: "Entry", align: "money", width: 68, widthShrink: 0, sortValue: item => number(item.entryTarget), format: item => number(item.entryTarget) ? compactMoney(item.entryTarget) : "Set", formatClass: "muted", editor: "number", editorParams: { min: 0, step: .01 }, onEdit: (item, value) => updateRadar(item, { entryTarget: Math.max(0, number(value)) }) },
    { key: "distance", label: "Δ Target", align: "money", width: 72, widthShrink: 0, sortValue: item => number(item.entryTarget) ? (number(item.currentPrice) - number(item.entryTarget)) / number(item.entryTarget) : 999, render: item => { const distance = number(item.entryTarget) ? ((number(item.currentPrice) - number(item.entryTarget)) / number(item.entryTarget)) * 100 : null; return <span className={distance === null ? "muted" : distance <= 0 ? "positive" : "negative"}>{distance === null ? "-" : `${distance > 0 ? "+" : ""}${distance.toFixed(1)}%`}</span>; } },
    { key: "plannedQty", label: "Want", align: "center", width: 68, widthShrink: 0, sortValue: item => number(item.plannedQty), render: item => { const qty = Math.max(1, number(item.plannedQty)); return <div className="ms-tabulator-stepper"><button type="button" aria-label={`Decrease planned quantity for ${item.name}`} disabled={qty <= 1} onClick={() => updateRadar(item, { plannedQty: Math.max(1, qty - 1) })}>−</button><span>{qty}</span><button type="button" aria-label={`Increase planned quantity for ${item.name}`} onClick={() => updateRadar(item, { plannedQty: qty + 1 })}>+</button></div>; } },
    { key: "sellers", label: "Sellers", align: "center", width: 56, widthShrink: 0, sortValue: item => number(latestMarket(item)?.currentSellers), format: item => latestMarket(item)?.currentSellers ?? "-" },
    { key: "marketQty", label: "Qty", align: "center", width: 48, widthShrink: 0, sortValue: item => number(latestMarket(item)?.currentQuantity), format: item => latestMarket(item)?.currentQuantity ?? "-" },
    { key: "tcg", label: "TCG Check", align: "money", width: 72, widthShrink: 0, sortValue: item => number(latestMarket(item)?.marketPrice), format: item => latestMarket(item)?.marketPrice ? compactMoney(latestMarket(item).marketPrice) : "-", title: item => latestMarket(item)?.checkedAt ? `Saved ${new Date(latestMarket(item).checkedAt).toLocaleString()}` : "No saved manual TCGplayer Market Check" },
    { key: "notes", label: "Notes", align: "center", width: 48, widthShrink: 0, sortValue: noteCount, render: item => { const count = noteCount(item); return <button type="button" className={`ms-tabulator-indicator${count ? " active" : ""}`} aria-label={`${count || "No"} notes for ${item.name}`} onClick={() => openDetail(item, "notes")}><span aria-hidden="true">▤</span>{count > 0 && <sup>{count}</sup>}</button>; } },
    { key: "history", label: "History", align: "center", width: 52, widthShrink: 0, sortValue: historyCount, render: item => { const count = historyCount(item); return <button type="button" className={`ms-tabulator-indicator${count ? " active" : ""}`} aria-label={`${count || "No"} price history snapshots for ${item.name}`} onClick={() => openDetail(item, "history")}><span aria-hidden="true">⌁</span>{count > 0 && <sup>{count}</sup>}</button>; } },
    { key: "actions", label: "Actions", sort: false, align: "actions", width: 112, widthShrink: 0, render: item => <div className="table-actions"><button onClick={() => setTrade(item)}>Buy</button><button className="danger ghost" onClick={() => { if (confirm(`Remove ${item.name} from Radar? This only removes the watched idea; it will not affect owned Positions.`)) updateSlice("radar", list => list.filter(row => row.id !== item.id)); }}>Remove</button></div> },
  ];
  const radarNotes = state.cardNotes.filter(note => state.radar.some(item => noteMatches(note, item))).length;
  return <><ViewHeader title="Radar" description="Watch ideas before money is committed. Buying creates or updates a Position while Radar keeps watching." /><div className="module-context-band radar-context"><SearchPanel initialQuery={params.get("query") || ""} onAdd={add} />{[{ label: "Watching", value: state.radar.length, detail: "Tracked ideas", preview: state.radar[0]?.name || "No watched ideas" }, { label: "Planned Entries", value: state.radar.filter(item => number(item.entryTarget) || number(item.plannedQty) > 1).length, detail: "Entry target or staged qty", preview: "Opportunity tracking" }, { label: "Notes", value: radarNotes, detail: "Linked decision notes", preview: radarNotes ? "Context attached" : "Needs plan" }].map(item => <article className="module-context-card" key={item.label}><span>{item.label}</span><strong>{item.value}</strong><small>{item.detail}</small><em>{item.preview}</em></article>)}</div><FilterBar value={filter} onChange={setFilter} /><TabulatorTable columns={columns} rows={rows} onRowClick={item => openDetail(item)} tableClass="ms-tabulator--radar" ariaLabel="Radar ideas" empty="Search above and add exact printings to start tracking ideas." initialSort={[{ column: "name", dir: "asc" }]} /><Modal open={Boolean(trade)} title="Buy from Radar" onClose={() => setTrade(null)}>{trade && <TradeForm item={trade} defaultQuantity={trade.plannedQty || 1} mode="buy" onCancel={() => setTrade(null)} onSubmit={(qty, price) => { try { updateState(current => buyFromRadar(current, trade, qty, price)); notices.show(`Bought ${qty} ${trade.name}. Radar will keep watching it.`); setTrade(null); } catch (error) { notices.show(error.message, "warning"); } }} />}</Modal><CardDetail item={detail} source="radar" initialPanel={detailPanel} onClose={() => { setDetail(null); setDetailPanel(""); }} /><Notice notice={notices.notice} onDismiss={notices.dismiss} /></>;
}

export function PositionsView() {
  const { state, updateSlice, updateState } = useAppState(); const [filter, setFilter] = useState(""); const [trade, setTrade] = useState(null); const [detail, setDetail] = useState(null); const notices = useNotices();
  const summary = calculatePortfolioSummary(state.specs, state.cash); const rows = state.specs.filter(item => [item.name, item.set_code, item.set_name].join(" ").toLowerCase().includes(filter.toLowerCase()));
  const edit = (item, key, value) => updateSlice("specs", list => list.map(row => row.id === item.id ? { ...row, [key]: number(value) } : row));
  const columns = [
    { key: "name", label: "Card", render: item => <button className="table-link" onClick={() => setDetail(item)}><CardIdentity item={item} /></button> },
    { key: "set_code", label: "Set", render: item => String(item.set_code || "-").toUpperCase() }, { key: "collector_number", label: "#" }, { key: "rarity", label: "Rarity", render: rarity }, { key: "color", label: "Color", render: color },
    { key: "buyPrice", label: "Buy", align: "money", sortValue: item => number(item.buyPrice), render: item => formatMoney(item.buyPrice) },
    { key: "currentPrice", label: "Now", align: "money", sortValue: item => number(item.currentPrice), render: item => formatMoney(item.currentPrice) }, { key: "qty", label: "Qty", align: "center", sortValue: item => number(item.qty) },
    { key: "age", label: "Age", align: "center", sortValue: item => ageDays(item.addedAt || item.createdAt), render: item => `${ageDays(item.addedAt || item.createdAt)}d` }, { key: "added", label: "Added", render: item => date(item.addedAt || item.createdAt) },
    { key: "value", label: "Value", align: "money", sortValue: item => number(item.qty) * number(item.currentPrice), render: item => formatMoney(number(item.qty) * number(item.currentPrice)) },
    { key: "pl", label: "P/L", align: "money", sortValue: item => (number(item.currentPrice) - number(item.buyPrice)) * number(item.qty), render: item => <span className={number(item.currentPrice) >= number(item.buyPrice) ? "positive" : "negative"}>{signedMoney((number(item.currentPrice) - number(item.buyPrice)) * number(item.qty))}</span> },
    { key: "plPct", label: "P/L %", align: "money", sortValue: item => number(item.buyPrice) ? ((number(item.currentPrice) - number(item.buyPrice)) / number(item.buyPrice)) * 100 : 0, render: item => percent(number(item.buyPrice) ? ((number(item.currentPrice) - number(item.buyPrice)) / number(item.buyPrice)) * 100 : 0) },
    { key: "exitTarget", label: "Target", align: "money", render: item => <input className="table-input" type="number" step="0.01" value={item.exitTarget || ""} placeholder="Set" onChange={event => edit(item, "exitTarget", event.target.value)} /> },
    { key: "distance", label: "Δ", align: "money", sortValue: item => number(item.exitTarget) ? ((number(item.currentPrice) - number(item.exitTarget)) / number(item.exitTarget)) * 100 : 999, render: item => number(item.exitTarget) ? percent(((number(item.currentPrice) - number(item.exitTarget)) / number(item.exitTarget)) * 100) : "-" },
    { key: "holdTime", label: "Hold", render: item => <input className="table-input hold-input" value={item.holdTime || ""} placeholder="Set" onChange={event => updateSlice("specs", list => list.map(row => row.id === item.id ? { ...row, holdTime: event.target.value } : row))} /> },
    { key: "notes", label: "Notes", align: "center", sortValue: item => state.cardNotes.filter(note => noteMatches(note, item)).length, render: item => state.cardNotes.filter(note => noteMatches(note, item)).length },
    { key: "history", label: "History", align: "center", sortValue: item => state.priceSnapshots.filter(row => row.cardId === item.id || row.cardId === item.scryfall_id).length, render: item => state.priceSnapshots.filter(row => row.cardId === item.id || row.cardId === item.scryfall_id).length },
    { key: "actions", label: "Actions", sort: false, align: "actions", render: item => <div className="table-actions"><button onClick={() => setTrade({ item, mode: "buy" })}>Buy</button><button className="danger" onClick={() => setTrade({ item, mode: "sell" })}>Sell</button><button className="danger ghost" onClick={() => { if (confirm(`Delete ${item.name} from Positions?`)) updateSlice("specs", list => list.filter(row => row.id !== item.id)); }}>Del</button></div> },
  ];
  function complete(qty, price) { try { updateState(current => trade.mode === "sell" ? sellPosition(current, trade.item, qty, price) : buyPosition(current, trade.item, qty, price)); notices.show(`${trade.mode === "sell" ? "Sold" : "Bought"} ${qty} ${trade.item.name}.`); setTrade(null); } catch (error) { notices.show(error.message, "warning"); } }
  const positionNotes = state.cardNotes.filter(note => state.specs.some(item => noteMatches(note, item))).length;
  return <><ViewHeader title="Positions" description="Owned positions only. Radar is for watch ideas before buying." /><MetricBand items={[{ label: "Portfolio Value", value: formatMoney(summary.value), detail: "Current marked value", preview: `${summary.openPositionCount} owned rows` }, { label: "Capital Deployed", value: formatMoney(summary.invested), detail: "Open position cost basis", preview: "Owned portfolio state" }, { label: "Open Positions", value: summary.openPositionCount, detail: "Cards currently owned", preview: state.specs[0]?.name || "No open positions" }, { label: "Notes", value: positionNotes, detail: "Linked decision notes", preview: positionNotes ? "Context attached" : "No notes yet" }]} /><FilterBar value={filter} onChange={setFilter} /><DataTable columns={columns} rows={rows} onRowClick={setDetail} empty="No owned positions yet. Buy an idea from Radar to begin." /><Modal open={Boolean(trade)} title={trade?.mode === "sell" ? "Confirm sale" : "Add to position"} onClose={() => setTrade(null)}>{trade && <TradeForm item={trade.item} mode={trade.mode} defaultQuantity={1} onCancel={() => setTrade(null)} onSubmit={complete} />}</Modal><CardDetail item={detail} source="positions" onClose={() => setDetail(null)} /><Notice notice={notices.notice} onDismiss={notices.dismiss} /></>;
}

function deriveSignals(state) {
  const observations = state.marketObservations || [];
  const lastCheck = item => observations.filter(row => row.cardId === item.id || row.cardId === item.scryfall_id).sort((a, b) => new Date(b.checkedAt) - new Date(a.checkedAt))[0];
  const positionRows = state.specs.map(item => {
    const price = number(item.currentPrice); const target = number(item.exitTarget); const distance = target ? ((price - target) / target) * 100 : 0; const missingPlanReasons = [!target && "Exit", !item.holdTime && "Hold"].filter(Boolean); const check = lastCheck(item); const stale = !check || ageDays(check.checkedAt) >= 30;
    const status = target && price >= target ? "Exit hit" : target && distance >= -10 ? "Exit near" : "Monitor";
    return { ...item, source: "Position", sourceKey: "portfolio", status, action: status === "Exit hit" ? "SELL / Position" : "Review", change: distance, targetValue: target, reasonLabel: missingPlanReasons.length ? `Missing ${missingPlanReasons.join(" + ")}` : status, missingPlanReasons, buckets: [...(status === "Exit hit" ? ["targetsHit"] : []), ...(status === "Exit near" ? ["approaching"] : []), ...(missingPlanReasons.length ? ["noPlan"] : []), ...(stale ? ["staleChecks"] : [])] };
  });
  const radarRows = state.radar.map(item => {
    const price = number(item.currentPrice); const target = number(item.entryTarget); const distance = target ? ((price - target) / target) * 100 : 0; const missingPlanReasons = [!target && "Entry"].filter(Boolean); const check = lastCheck(item); const stale = !check || ageDays(check.checkedAt) >= 30;
    const status = target && price <= target ? "Entry hit" : target && distance <= 10 ? "Entry near" : "Monitor";
    return { ...item, source: "Radar", sourceKey: "radar", status, action: status === "Entry hit" ? "BUY / Radar" : "Review", change: distance, targetValue: target, reasonLabel: missingPlanReasons.length ? "Missing Entry" : status, missingPlanReasons, buckets: [...(status === "Entry hit" ? ["targetsHit"] : []), ...(status === "Entry near" ? ["approaching"] : []), ...(missingPlanReasons.length ? ["noPlan"] : []), ...(stale ? ["staleChecks"] : [])] };
  });
  return [...positionRows, ...radarRows].sort((a, b) => (a.status === "Monitor") - (b.status === "Monitor") || Math.abs(a.change) - Math.abs(b.change));
}

export function SignalsView() {
  const { state } = useAppState(); const [filter, setFilter] = useState(""); const [detail, setDetail] = useState(null); const rows = deriveSignals(state).filter(row => row.buckets.length && [row.name, row.status, row.action, row.source].join(" ").toLowerCase().includes(filter.toLowerCase()));
  const columns = [
    { key: "name", label: "Card", render: item => <button className="table-link" onClick={() => setDetail(item)}><CardIdentity item={item} /></button> }, { key: "set_code", label: "Set", render: item => String(item.set_code || "-").toUpperCase() }, { key: "collector_number", label: "#" }, { key: "foil", label: "Fin", render: item => item.foil ? "F" : "N" },
    { key: "source", label: "Source" }, { key: "action", label: "Action" }, { key: "reasonLabel", label: "Why", render: item => <span className={`status-pill ${item.status.includes("hit") ? "action" : ""}`}>{item.reasonLabel || item.status}</span> },
    { key: "currentPrice", label: "Now", align: "money", render: item => formatMoney(item.currentPrice) }, { key: "targetValue", label: "Target", align: "money", render: item => item.targetValue ? formatMoney(item.targetValue) : "-" },
    { key: "change", label: "Δ Target", align: "money", sortValue: item => item.change, render: item => item.targetValue ? percent(item.change) : "-" },
    { key: "market", label: "Market", align: "money", sortValue: item => number(state.marketObservations.find(row => row.cardId === item.id)?.marketPrice), render: item => { const check = state.marketObservations.find(row => row.cardId === item.id); return check?.marketPrice ? formatMoney(check.marketPrice) : "Due"; } },
    { key: "actions", label: "Actions", sort: false, align: "actions", render: item => <div className="table-actions"><button onClick={() => setDetail(item)}>Detail</button><a className="button secondary" href={`https://scryfall.com/card/${String(item.scryfall_id || item.id).replace(/\|.*$/, "")}`} target="_blank" rel="noreferrer">View</a></div> },
  ];
  const hits = rows.filter(row => row.status.includes("hit")); const near = rows.filter(row => row.status.includes("near")); const noPlan = rows.filter(row => row.buckets.includes("noPlan")); const stale = rows.filter(row => row.buckets.includes("staleChecks"));
  return <><ViewHeader title="Signals" description="What needs attention today across Radar and Positions." /><MetricBand items={[{ label: "Targets Hit", value: hits.length, detail: "Immediate buy/sell review" }, { label: "Approaching", value: near.length, detail: "Near or closest target" }, { label: "No Plan", value: noPlan.length, detail: "Missing required fields" }, { label: "Stale Checks", value: stale.length, detail: "Missing or 30+ days old" }]} /><FilterBar value={filter} onChange={setFilter} /><DataTable columns={columns} rows={rows} onRowClick={setDetail} empty="Set entry or exit targets to create useful signals." /><CardDetail item={detail} source={detail?.source === "Radar" ? "radar" : "positions"} onClose={() => setDetail(null)} /></>;
}

export function TransactionsView() {
  const { state } = useAppState(); const [filter, setFilter] = useState(""); const [type, setType] = useState(""); const [detail, setDetail] = useState(null); const rows = state.transactions.filter(tx => (!type || tx.type === type) && [tx.name, tx.set_code, tx.notes, tx.type].join(" ").toLowerCase().includes(filter.toLowerCase()));
  const buys = state.transactions.filter(tx => tx.type === "BUY"); const sells = state.transactions.filter(tx => tx.type === "SELL");
  const columns = [{ key: "name", label: "Card", render: item => <CardIdentity item={item} /> }, { key: "set_code", label: "Set", render: item => String(item.set_code || "-").toUpperCase() }, { key: "collector_number", label: "#" }, { key: "rarity", label: "Rarity", render: rarity }, { key: "color", label: "Color", render: color }, { key: "price", label: "Price", align: "money", render: item => formatMoney(item.price) }, { key: "quantity", label: "Qty", align: "center" }, { key: "total", label: "Total", align: "money", sortValue: item => number(item.quantity) * number(item.price), render: item => <span className={item.type === "SELL" ? "positive" : "negative"}>{item.type === "SELL" ? "+" : "-"}{formatMoney(number(item.quantity) * number(item.price))}</span> }, { key: "balanceAfter", label: "Balance", align: "money", render: item => Number.isFinite(Number(item.balanceAfter)) ? formatMoney(item.balanceAfter) : "-" }, { key: "realizedPL", label: "Realized", align: "money", render: item => item.type === "SELL" && Number.isFinite(Number(item.realizedPL)) ? signedMoney(item.realizedPL) : "-" }, { key: "date", label: "Date", render: item => date(item.date) }, { key: "type", label: "Type", render: item => <span className={`tx-pill ${item.type.toLowerCase()}`}>{item.type}</span> }];
  const bought = buys.reduce((sum, tx) => sum + number(tx.quantity) * number(tx.price), 0); const sold = sells.reduce((sum, tx) => sum + number(tx.quantity) * number(tx.price), 0);
  return <><ViewHeader title="Transactions" description="Compact ledger for buys, sells, balances, fees, and realized outcomes." /><MetricBand items={[{ label: "Buys", value: buys.length, detail: `${formatMoney(bought)} deployed` }, { label: "Sells", value: sells.length, detail: `${formatMoney(sold)} returned` }, { label: "Net Cash Flow", value: signedMoney(sold - bought), detail: "Sells minus buys" }, { label: "Recent Activity", value: state.transactions[0] ? date(state.transactions[0].date) : "-", detail: state.transactions[0]?.name || "No transactions" }]} /><FilterBar value={filter} onChange={setFilter}><label><span>Type</span><select value={type} onChange={event => setType(event.target.value)}><option value="">All types</option><option>BUY</option><option>SELL</option></select></label></FilterBar><DataTable columns={columns} rows={rows} onRowClick={item => setDetail([...state.specs, ...state.radar].find(row => row.scryfall_id === item.scryfall_id || row.name === item.name) || { ...item, currentPrice: item.price })} empty="No transactions yet. Buys and sells will appear here automatically." /><CardDetail item={detail} source="positions" onClose={() => setDetail(null)} /></>;
}

export function HistoryView() {
  const { state } = useAppState(); const [filter, setFilter] = useState(""); const [type, setType] = useState(""); const [detail, setDetail] = useState(null);
  const allEvents = [
    ...state.transactions.map(tx => ({ ...tx, kind: "transaction", eventType: tx.type, summary: `${tx.type === "BUY" ? "Bought" : "Sold"} ${tx.quantity} at ${formatMoney(tx.price)}${Number.isFinite(Number(tx.balanceAfter)) ? ` / Balance ${formatMoney(tx.balanceAfter)}` : ""}` })),
    ...state.radar.filter(item => item.addedDate || item.createdAt).map(item => ({ ...item, id: `radar-${item.id}`, kind: "radar", name: item.name, date: item.addedDate || item.createdAt, price: item.currentPrice, eventType: "RADAR", summary: "Added to Radar" })),
    ...state.cardNotes.map(note => ({ ...note, id: `note-${note.id}`, kind: "note", name: note.cardName, date: note.updatedAt || note.createdAt, eventType: "NOTE", summary: note.text })),
    ...(state.thesisNotes || []).map(note => ({ ...note, id: `thesis-${note.id}`, kind: "note", name: note.cardName || "General", date: note.updatedAt || note.createdAt, eventType: "THESIS", summary: note.conviction || note.text || "Saved thesis" })),
  ].filter(event => event.date).sort((a, b) => new Date(b.date) - new Date(a.date));
  const events = allEvents.filter(event => (!type || event.kind === type) && [event.name, event.summary, event.eventType].join(" ").toLowerCase().includes(filter.toLowerCase()));
  const columns = [{ key: "name", label: "Card" }, { key: "set_code", label: "Set", render: item => String(item.set_code || "-").toUpperCase() }, { key: "collector_number", label: "#" }, { key: "rarity", label: "Rarity", render: rarity }, { key: "color", label: "Color", render: color }, { key: "price", label: "Price", align: "money", render: item => item.price ? formatMoney(item.price) : "-" }, { key: "date", label: "Date", render: item => new Date(item.date).toLocaleString() }, { key: "eventType", label: "Type", render: item => <span className="status-pill">{item.eventType}</span> }, { key: "notes", label: "Notes", render: item => item.eventType === "NOTE" ? item.summary : (item.notes || "-") }, { key: "summary", label: "Detail" }];
  return <><ViewHeader title="History" description="Recent activity and learning trail across transactions, radar, and notes." /><MetricBand items={[{ label: "Events", value: allEvents.length, detail: "Reviewable records" }, { label: "Trades", value: state.transactions.length, detail: "Buy and sell events" }, { label: "Lessons / Review", value: state.cardNotes.length + (state.thesisNotes || []).length, detail: "Saved decision notes" }, { label: "Notes", value: state.cardNotes.length, detail: "Card memory" }]} /><FilterBar value={filter} onChange={setFilter} placeholder="Event, card, detail"><label><span>Type</span><select value={type} onChange={event => setType(event.target.value)}><option value="">All events</option><option value="transaction">Transactions</option><option value="radar">Radar</option><option value="note">Notes</option></select></label></FilterBar><DataTable columns={columns} rows={events} onRowClick={event => { const item = [...state.specs, ...state.radar].find(row => row.scryfall_id === event.scryfall_id || row.id === event.cardId || row.name === event.name); if (item) setDetail(item); }} empty="Activity will appear here as you work." /><CardDetail item={detail} source="positions" onClose={() => setDetail(null)} /></>;
}

export function DashboardView() {
  const { state } = useAppState(); const navigate = useNavigate(); const [detail, setDetail] = useState(null); const summary = calculatePortfolioSummary(state.specs, state.cash); const allSignals = deriveSignals(state); const signals = allSignals.filter(row => row.buckets.length);
  const queueRow = (item, reason) => ({ ...item, title: `${item.name} - ${printing(item)}`, detail: `${reason} - ${formatMoney(item.currentPrice)}${item.targetValue ? ` -> ${item.sourceKey === "radar" ? "Entry" : "Target"} ${formatMoney(item.targetValue)}` : ""}` });
  const closest = (source, status, label) => allSignals.filter(row => row.sourceKey === source && number(row.targetValue) && row.status !== status).sort((a, b) => Math.abs(a.change) - Math.abs(b.change)).slice(0, 5).map(item => queueRow(item, label));
  const noteKeys = new Set(); const notes = [...state.cardNotes].sort((a, b) => new Date(b.createdAt || b.updatedAt) - new Date(a.createdAt || a.updatedAt)).filter(note => { const key = note.cardKey || note.cardId || `${note.cardName}|${note.set_code}|${note.collector_number}`; if (noteKeys.has(key)) return false; noteKeys.add(key); return true; }).slice(0, 5).map(note => { const item = [...state.specs, ...state.radar].find(row => row.id === note.cardId || row.scryfall_id === note.scryfall_id || row.name === note.cardName); return { ...(item || note), title: `${note.cardName || item?.name || "General note"}${item ? ` - ${printing(item)}` : ""}`, detail: `${String(note.text || "").slice(0, 72)} / ${date(note.createdAt || note.updatedAt)}`, static: !item }; });
  const queues = [
    ["Exit Hits", signals.filter(row => row.status === "Exit hit").slice(0, 5).map(item => queueRow(item, "Exit Hit")), "No exit hits."],
    ["Entry Hits", signals.filter(row => row.status === "Entry hit").slice(0, 5).map(item => queueRow(item, "Entry Hit")), "No entry hits."],
    ["Exit Near", [...signals.filter(row => row.status === "Exit near").map(item => queueRow(item, "Exit Near")), ...closest("portfolio", "Exit near", "Exit Watch")].slice(0, 5), "Nothing near exit."],
    ["Entry Near", [...signals.filter(row => row.status === "Entry near").map(item => queueRow(item, "Entry Near")), ...closest("radar", "Entry near", "Entry Watch")].slice(0, 5), "Nothing near entry."],
    ["Market Checks Due", signals.filter(row => row.buckets.includes("staleChecks")).slice(0, 5).map(item => queueRow(item, "Market Check Due")), "No market checks due."],
    ["Hold Reviews Due", signals.filter(row => row.sourceKey === "portfolio" && row.missingPlanReasons.includes("Hold")).slice(0, 5).map(item => queueRow(item, "Hold Missing")), "No hold reviews due."],
    ["Missing Plans", signals.filter(row => row.buckets.includes("noPlan")).slice(0, 5).map(item => queueRow(item, item.reasonLabel)), "Plans look filled in."],
    ["Recent Notes", notes, "No recent notes."],
  ];
  return <section className="dashboard-view"><ViewHeader title="Dashboard" description="What to inspect first today." /><div className="metric-grid dashboard-state-grid"><div className="metric-card"><span>Cash</span><strong>{formatMoney(summary.cash)}</strong><small>Available</small></div><div className={`metric-card metric-card--${summary.profitLoss > 0 ? "positive" : summary.profitLoss < 0 ? "negative" : "neutral"}`}><span>Equity / Open P&amp;L</span><strong>{formatMoney(summary.totalEquity)} / {summary.profitLoss ? signedMoney(summary.profitLoss) : formatMoney(0)}</strong><small>{percent(summary.profitLossPercent)}</small></div><div className="metric-card"><span>Tracked Printings</span><strong>{state.specs.length + state.radar.length}</strong><small>{state.specs.length} Positions, {state.radar.length} Radar</small></div><button type="button" className="metric-card metric-card--action" onClick={() => navigate("/signals")}><span>Signals</span><strong>{signals.length} active</strong><small>Open Signals</small></button></div><div className="scan-grid dashboard-work-grid">{queues.map(([title, rows, empty]) => <section className="scan-panel" key={title}><h4>{title}</h4>{rows.length ? rows.map((item, index) => item.static ? <div className="scan-row dashboard-queue-row" key={`${title}-${index}`}><strong>{item.title}</strong><span>{item.detail}</span></div> : <button type="button" className="scan-row dashboard-queue-row attention-queue-row" key={`${title}-${item.id}-${index}`} onClick={() => setDetail(item)}><strong>{item.title}</strong><span>{item.detail}</span></button>) : <div className="empty-state compact">{empty}</div>}</section>)}</div><CardDetail item={detail} source={detail?.sourceKey || "portfolio"} onClose={() => setDetail(null)} /></section>;
}

export function AdminView() {
  const { state, updateState, createBackup, parseBackupText, restoreBackup } = useAppState(); const [preview, setPreview] = useState(null); const notices = useNotices();
  const reconciliation = useMemo(() => dataFoundation.buildReconciliationReport({ specs: state.specs, transactions: state.transactions }), [state.specs, state.transactions]);
  function download() { const blob = new Blob([JSON.stringify(createBackup(), null, 2)], { type: "application/json" }); const link = document.createElement("a"); link.href = URL.createObjectURL(blob); link.download = `manaspec-backup-${new Date().toISOString().slice(0, 10)}.json`; link.click(); URL.revokeObjectURL(link.href); notices.show("Backup exported."); }
  async function choose(event) { const file = event.target.files?.[0]; if (!file) return; const result = parseBackupText(await file.text()); if (!result.ok) notices.show(result.message, "warning"); else setPreview(result.backup); event.target.value = ""; }
  async function refresh() { try { notices.show("Refreshing Scryfall prices…"); const unique = new Map([...state.specs, ...state.radar].map(item => [item.id, item])); const result = await refreshTrackedPrices([...unique.values()]); const map = new Map(result.items.map(item => [item.id, item])); const checkedAt = new Date().toISOString(); const day = checkedAt.slice(0, 10); updateState(current => { const newSnapshots = result.items.map(item => ({ date: day, cardId: item.scryfall_id || item.id, name: item.name, set: item.set_code, foil: Boolean(item.foil), price: number(item.currentPrice), source: "scryfall", savedAt: checkedAt })).filter(snapshot => snapshot.price > 0 && !current.priceSnapshots.some(row => row.date === day && row.cardId === snapshot.cardId && Boolean(row.foil) === snapshot.foil)); return { ...current, specs: current.specs.map(item => map.get(item.id) || item), radar: current.radar.map(item => map.get(item.id) || item), priceSnapshots: [...current.priceSnapshots, ...newSnapshots], priceRefreshStatus: { checkedAt, updatedCount: result.updated } }; }); notices.show(`Updated ${result.updated} tracked printing prices.`); } catch (error) { notices.show(error.message, "warning"); } }
  return <><ViewHeader title="Admin" description="Protect local data and manage controlled maintenance actions." /><div className="admin-grid parity-admin-grid"><section className="admin-panel"><h4>Cash</h4><p>Reset only the paper trading cash balance. Positions, Radar, notes, and history remain intact.</p><strong>{formatMoney(state.cash)}</strong><button className="danger" onClick={() => { if (confirm("Reset cash to $10,000?")) updateState(current => ({ ...current, cash: 10000 })); }}>Reset Cash</button></section><section className="admin-panel"><h4>Data Safety</h4><p>Export a complete local backup or restore a previously exported ManaSpec file.</p><div className="button-row"><button onClick={download}>Export Backup</button><label className="button secondary">Import Backup<input hidden type="file" accept="application/json,.json" onChange={choose} /></label></div></section><section className="admin-panel"><h4>Prices</h4><p>Refresh tracked Scryfall prices and save today’s price-history snapshots.</p><button onClick={refresh}>Run Price Audit</button><small>{state.priceRefreshStatus?.checkedAt ? `Last run ${new Date(state.priceRefreshStatus.checkedAt).toLocaleString()}` : "No audit recorded"}</small></section><section className="admin-panel"><h4>Integrations</h4><p>External source management is reserved for a later product phase.</p><button disabled>Manage Sources</button><small>Not available in this spike</small></section></div><div className="admin-diagnostics"><section className="admin-card"><h4>Ledger reconciliation</h4><p>Read-only comparison of current Positions against transaction-projected holdings.</p><dl><div><dt>Findings</dt><dd className={reconciliation.summary.findingCount ? "negative" : "positive"}>{reconciliation.summary.findingCount}</dd></div><div><dt>Matched</dt><dd>{reconciliation.summary.matched || 0}</dd></div><div><dt>Projection issues</dt><dd>{reconciliation.projectionIssues.length}</dd></div></dl></section><section className="admin-card"><h4>React storage diagnostics</h4><p>Data remains local to this browser. Use exports for durable backup and device transfer.</p><dl><div><dt>Positions</dt><dd>{state.specs.length}</dd></div><div><dt>Radar</dt><dd>{state.radar.length}</dd></div><div><dt>Snapshots</dt><dd>{state.priceSnapshots.length}</dd></div></dl></section></div><Modal open={Boolean(preview)} title="Restore ManaSpec backup?" onClose={() => setPreview(null)}>{preview && <div className="react-form"><p>This will replace current local data. An emergency pre-import copy is retained by the storage layer.</p><dl className="backup-counts">{Object.entries(preview.counts).map(([key, value]) => <div key={key}><dt>{key}</dt><dd>{value}</dd></div>)}</dl><div className="modal-actions"><button className="secondary" onClick={() => setPreview(null)}>Cancel</button><button onClick={() => { try { restoreBackup(preview); setPreview(null); notices.show("Backup restored."); } catch (error) { notices.show(error.message, "warning"); } }}>Restore backup</button></div></div>}</Modal><Notice notice={notices.notice} onDismiss={notices.dismiss} /></>;
}
